#define ZORRO_IDS_COUNT 461

/*
 * zorro_lookup_manuf() - Etsi valmistajan nimi
 * Palauttaa nimen tai NULL jos ei loydy.
 */
static const char *
zorro_lookup_manuf(unsigned short manuf)
{
    const struct zorro_id_entry *e;
    for (e = zorro_ids; e->manuf_name != NULL; e++)
        if (e->manuf == manuf && e->prod == -1)
            return e->manuf_name;
    return NULL;
}

/*
 * zorro_lookup_product() - Etsi tuotteen nimi
 * prod on 8-bittinen tuotenumero sellaisenaan (ei shiftattu).
 * Palauttaa nimen tai NULL jos ei loydy.
 */
static const char *
zorro_lookup_product(unsigned short manuf, unsigned char prod)
{
    const struct zorro_id_entry *e;
    for (e = zorro_ids; e->manuf_name != NULL; e++)
        if (e->manuf == manuf && e->prod == (short)prod)
            return e->prod_name;
    return NULL;
}

#endif /* ZORRO_IDS_H */
